with open(PATH, "r", encoding="utf-8") as f:
    data = json.load(f)
count = 0
for key, qs in QUESTIONS.items():
    if key not in data:
        print(f"⚠ {key} not found"); continue
    new_list = []
    for i, (qt, opts, ci, expl) in enumerate(qs):
        options = []
        for j, o in enumerate(opts):
            options.append({"text": o, "is_correct": j == ci, "data_i18n": None})
        new_list.append({
            "question_number": i + 1, "question_text": qt, "attempted": 2,
            "data_i18n": None, "options": options, "explanation": expl
        })
    data[key]["quiz_questions"] = new_list
    count += 1
with open(PATH, "w", encoding="utf-8") as f:
    json.dump(data, f, indent=2, ensure_ascii=False)
print(f"✅ Integrated Science U7: replaced questions for {count} lessons")
